CREATE TABLE IF NOT EXISTS `courses` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '课程ID（自增主键）',
  `course_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '课程名称',
  `teacher_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '任课教师姓名',
  `course_time` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '上课时间（如 "周三 08:00-09:40"）',
  `course_location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '上课地点（如 "教学楼J302"）',
  `weekday` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '上课星期',
  `time_range` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '上课时间段',
  `start_date` date DEFAULT NULL COMMENT '课程开始日期（与前端现有数据兼容）',
  `end_date` date DEFAULT NULL COMMENT '课程结束日期（与前端现有数据兼容）',
  `start_time` time DEFAULT NULL COMMENT '上课开始时间（与前端现有数据兼容）',
  `end_time` time DEFAULT NULL COMMENT '上课结束时间（与前端现有数据兼容）',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_course_weekday` (`course_name`,`weekday`),
  KEY `idx_course_name` (`course_name`) COMMENT '课程名称普通索引，加速按名称查询',
  KEY `idx_teacher_name` (`teacher_name`) COMMENT '任课教师姓名索引，加速按教师查询'
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='课程管理表 - 存储课程信息数据';

