CREATE TABLE IF NOT EXISTS `users` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '用户ID（自增主键）',
  `username` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户账号',
  `password` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '账号密码（建议存储加盐哈希值）',
  `name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户姓名（中文简体）',
  `user_type` enum('teacher','student') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'student' COMMENT '用户类型：teacher=教师(超级账号), student=学生',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_username` (`username`) COMMENT '用户账号唯一索引'
) ENGINE=InnoDB AUTO_INCREMENT=74 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='用户表 - 存储用户账号信息';

